    43→/** A Jam boolean constant, also used to represent a boolean token for parsing. */
    44→class BoolConstant implements Token, Constant, JamVal {
    45→  private boolean value;
    46→  private BoolConstant(boolean b) { value = b; }
    47→  
    48→  /** Singleton pattern definitions. */
    49→  public static final BoolConstant FALSE = new BoolConstant(false);
    50→  public static final BoolConstant TRUE = new BoolConstant(true);
    51→  
    52→  /** A factory method that returns BoolConstant corresponding to b. It is atatic because
    53→    * it does not depend on this. */
    54→  public static BoolConstant toBoolConstant(boolean b) { 
    55→    if (b) return TRUE; 
    56→    else return FALSE;
    57→  }
    58→  
    59→  public boolean value() { return value; }
    60→  public BoolConstant not() { if (this == FALSE) return TRUE; else return FALSE; }
    61→  
    62→  public <ResType> ResType accept(ASTVisitor<ResType> av) { return av.forBoolConstant(this); }
    63→  public <ResType> ResType accept(JamValVisitor<ResType> jv) { return jv.forBoolConstant(this); }
    64→  public String toString() { return String.valueOf(value); }
    65→}
