    69→/** Interface for all Pure Lists.
    70→  * PureList<ElemType> := Empty<ElemType> | Cons<ElemType>
    71→  */
    72→interface PureList<ElemType> {
    73→  abstract PureList<ElemType> cons(ElemType o);
    74→  abstract PureList<ElemType> empty();
    75→  abstract <ResType> ResType accept(PureListVisitor<ElemType, ResType> v);
    76→  abstract String toStringHelp();
    77→  abstract PureList<ElemType> append(PureList<ElemType> addedElts);
    78→}
    79→
    80→/** The visitor interface for the type PureList<T> */
    81→interface PureListVisitor<ElemType, ResType> {
    82→  ResType forEmpty(Empty<ElemType> e);
    83→  ResType forCons(Cons<ElemType> c);
    84→}
    85→
    86→/** An abstract class that factors out code common to classes Empty<T> and Cons<T> */
    87→abstract class PureListClass<ElemType> implements PureList<ElemType> {
    88→  public PureList<ElemType> cons(ElemType o) { return new Cons<ElemType>(o,this); }
    89→  public PureList<ElemType> empty() { return new Empty<ElemType>(); }
    90→  public abstract <ResType> ResType accept(PureListVisitor<ElemType, ResType> v);  
