    94→/** The empty PureList<T> class */
    95→class Empty<ElemType> extends PureListClass<ElemType> {
    96→  public <ResType> ResType accept(PureListVisitor<ElemType,ResType> v) { return v.forEmpty(this); }
    97→  public PureList<ElemType> append(PureList<ElemType> addedElts) { return addedElts; }
    98→  
    99→  /** overrides inherited equals because Empty is not a singleton! */
   100→  public boolean equals(Object other) { 
   101→    return (other != null && other.getClass() == this.getClass());
   102→  }
   103→  
   104→  public String toString() { return "()"; }
   105→  public String toStringHelp() { return ""; }
   106→}
   107→
   108→/** The non-empty PureList<T> class */
   109→class Cons<ElemType> extends PureListClass<ElemType> {
   110→  ElemType first;
   111→  PureList<ElemType> rest;
   112→  Cons(ElemType f, PureList<ElemType> r) { first = f; rest = r; }
   113→  
   114→  public <ResType> ResType accept(PureListVisitor<ElemType,ResType> v) { return v.forCons(this); }
   115→  public PureList<ElemType> append(PureList<ElemType> addedElts) { 
   116→    return new Cons<ElemType>(first, rest.append(addedElts)); 
   117→  }
   118→  
   119→  public ElemType first() { return first; }
   120→  public PureList<ElemType> rest() { return rest; }
   121→  
   122→  public boolean equals(Object other) { 
   123→    if (other == empty() || this.getClass() != other.getClass()) return false;
   124→    Cons otherCons = (Cons) other;
   125→    return first.equals(otherCons.first) && rest.equals(otherCons.rest);
   126→  }
   127→  
   128→  public String toString() { return "(" + first + rest.toStringHelp() + ")"; }
   129→  
   130→  public String toStringHelp() { return " " + first + rest.toStringHelp(); }
   131→}
