   341→/* A class representing a Jam operator Token. */
   342→class OpToken implements Token {
   343→  private String symbol;
   344→  private boolean isUnOp;
   345→  private boolean isBinOp;
   346→  /** the corresponding unary operator in UnOp */
   347→  private UnOp unOp;
   348→  /** the corresponding binary operator in BinOp */
   349→  private BinOp binOp;
   350→  
   351→  private OpToken(String s, boolean iu, boolean ib, UnOp u, BinOp b) {
   352→    symbol = s; isUnOp = iu; isBinOp = ib; unOp = u; binOp = b; 
   353→  }
   354→  
   355→  /** factory method for constructing OpToken serving as both UnOp and BinOp */
   356→  public static OpToken newBothOpToken(UnOp u, BinOp b) {
   357→    return new OpToken(u.toString(), true, true, u, b);
   358→  }
   359→  
   360→  /** factory method for constructing OpToken serving as BinOp only */
   361→  public static OpToken newBinOpToken(BinOp b) {
   362→    return new OpToken(b.toString(), false, true, null, b);
   363→  }
   364→  
   365→  /** factory method for constructing OpToken serving as UnOp only */
   366→  public static OpToken newUnOpToken(UnOp u) {
   367→    return new OpToken(u.toString(), true, false, u, null);
   368→  }
   369→  public String symbol() { return symbol; }
   370→  public boolean isUnOp() { return isUnOp; }
   371→  public boolean isBinOp() { return isBinOp; }
   372→  public UnOp toUnOp() { 
   373→    if (unOp == null) 
   374→      throw new NoSuchElementException("OpToken " + this + " does not denote a unary operator");
   375→    return unOp;
   376→  }
   377→  
   378→  public BinOp toBinOp() { 
   379→    if (binOp == null) 
   380→      throw new NoSuchElementException("OpToken " + this + " does not denote a binary operator");
   381→    return binOp; 
   382→  }
   383→  public String toString() { return symbol; }
   384→}
