public JamVal forJamClosure(JamClosure closure) {
  Map map = closure.code();
  Variable[] vars = map.vars();
  if (vars.length != args.length) {
    throw new EvalException("Function arity mismatch: expected " + vars.length + ", got " + args.length);
  }
  PureList<Binding> env = closure.env();
  for (int i = 0; i < vars.length; i++) {
    Binding b = evalVisitor.newBinding(vars[i], args[i]);
    env = env.cons(b);
  }
  EvalVisitor newVisitor = evalVisitor.newVisitor(env);
